import{_ as a}from"./plugin-vue_export-helper-c27b6911.js";import{r as i,o as r,c as d,a as e,b as o,d as s,e as t}from"./app-be253e4c.js";const n={},c=t(`<h1 id="redis-key命名规范" tabindex="-1"><a class="header-anchor" href="#redis-key命名规范" aria-hidden="true">#</a> Redis-Key命名规范</h1><h2 id="建议风格一致" tabindex="-1"><a class="header-anchor" href="#建议风格一致" aria-hidden="true">#</a> 建议风格一致</h2><p>key的书写风格保持一致，常见的变量风格有：</p><ul><li>同时大驼峰，例如：<code>UserAdmin</code></li><li>同时小驼峰，例如：<code>userAdmin</code></li><li>同时下划线，例如：<code>user_admin</code></li></ul><p>做到项目级别的风格统一; <strong>个人建议采用小驼峰</strong></p><h2 id="长度约束" tabindex="-1"><a class="header-anchor" href="#长度约束" aria-hidden="true">#</a> 长度约束</h2><ul><li>key不能太长也不能太短,合理设计</li><li><strong>键名越长越占资源，太短可读性太差</strong></li></ul><h2 id="以冒号分开" tabindex="-1"><a class="header-anchor" href="#以冒号分开" aria-hidden="true">#</a> 以冒号分开</h2><ul><li><p>redis-key 单词与单词之间以，冒号<code>:</code>分开</p></li><li><p>市面上的redis可视化工具，冒号<code>:</code>比较容易进行下级选择和业务分类</p></li></ul><h2 id="使用命名空间" tabindex="-1"><a class="header-anchor" href="#使用命名空间" aria-hidden="true">#</a> 使用命名空间</h2><p><strong>一个项目一个命名空间，项目内业务不同命名空间也不同</strong>。</p><p>一般情况下：</p><ul><li><p>第一段放置项目名或缩写 ，例如： userAdmin</p></li><li><p>第二段把表名转换为key前缀，例如： user</p></li><li><p>第三段放置用于区分区key的字段,对应mysql中的主键的列名,例如：id</p></li><li><p>第四段放置主键值,如18,16</p></li></ul><p>结合起来 PRO:USER:UID:18 直接意思就是，xx项目下的xx表中xx字段对应的值</p><p>以上是单机模式，当在redis集群中使用相关业务时候，常常需要将部分业务散列到相同的slot中，这时hash tag的作用就显得 非常重要； <strong>做法是在key中添加<code>{}</code>前缀<code>prefix</code></strong></p><h2 id="key分发模型" tabindex="-1"><a class="header-anchor" href="#key分发模型" aria-hidden="true">#</a> key分发模型</h2><p>key空间分为16384个槽，有效地设置了16384个主节点的簇大小的上限（但建议的最大节点大小约为1000个节点）。 集群中的每个主节点处理16384个散列槽的子集。</p><p>当没有正在进行的集群重新配置时（即散列插槽从一个节点移动到另一个节点），集群是稳定的。</p><p>当集群稳定时，单个节点将提供单个散列槽（但是，在网络分裂或故障的情况下，服务节点可以有一个或多个将替换它的从属，并且可以用于扩展读取过时数据的读取操作）。 用于将键映射到散列槽的基本算法如下（读取此规则的散列标记异常的下一段）：</p><div class="language-bash" data-ext="sh"><pre class="language-bash"><code>HASH_SLOT <span class="token operator">=</span> CRC16<span class="token punctuation">(</span>key<span class="token punctuation">)</span> mod <span class="token number">16384</span>
</code></pre></div><ul><li>Name：XMODEM（也称为ZMODEM或CRC-16 / ACORN）</li><li>Width：16位</li><li>Poly：1021（实际上是x^16 + x^12 + x^5 + 1）</li><li>Initialization：0000</li><li>Reflect Input byte：False</li><li>Reflect Output CRC：错误</li><li>Xor constant to output CRC：0000</li><li>Output for &quot;123456789&quot;：31C3</li></ul><p>使用16个CRC16输出位中的14个（这就是为什么在上面的公式中存在模16384运算的原因）。</p><p>在实际测试中，CRC16在16384个插槽中均匀分配不同类型的key时表现非常出色。</p><h2 id="键哈希标签" tabindex="-1"><a class="header-anchor" href="#键哈希标签" aria-hidden="true">#</a> 键哈希标签</h2><p>计算用于实现散列标记的散列槽有一个例外。 散列标记是一种确保在同一散列槽中分配多个key的方法。这用于在Redis集群中实现多键操作。 为了实现散列标签，在某些条件下以稍微不同的方式计算key的散列槽。</p><p>如果key包含一个<code>{...}</code>模式仅是<code>{and}</code>之间的子串 ，以获得散列slot被散列。</p><p>但是，由于可能存在多次出现<code>{or}</code>，以下规则很好地指定了算法：</p><ul><li>如果key包含一个{字符。</li><li>如果{右边有一个字符}</li><li>如果第一次出现{和第一次出现}之间有一个或多个字符。</li></ul><p>如果满足条件三，不是对key进行散列，而是仅对第一次出现<code>{和第一次出现}</code>之间的内容进行散列。</p><p>例如：</p><ul><li><p>两个key<code>{user1000}.following</code>和<code>{user1000}.followers</code>将散列到相同的散列slot， 因为只有在子串user1000会计算散列slot。</p></li><li><p>对于键<code>foo{}{bar}</code>，通常将整个键进行哈希处理，因为第一次出现<code>{右侧是}</code>，而中间没有字符。</p></li><li><p>对于键<code>foo{{bar}}zap</code>，子串{bar将被散列，因为它是第一次出现<code>{和右边第一次出现}</code>之间的子串。</p></li><li><p>对于<code>keyfoo{bar}{zap}</code>的子串bar将被散列，算法在第一个有效或无效（无内部字节）匹配<code>{and}</code>后停止匹配。</p></li></ul><p>该算法的结果是，如果key开头<code>{}</code>，则保证整个散列。当使用二进制数据作为键名时，这很有用。</p><h2 id="使用规范" tabindex="-1"><a class="header-anchor" href="#使用规范" aria-hidden="true">#</a> 使用规范</h2><p>在项目中，redis属于高频使用，遇到了各种各样的redis问题，针对自身情况梳理了一个redis使用规范。</p><h3 id="key的设计" tabindex="-1"><a class="header-anchor" href="#key的设计" aria-hidden="true">#</a> Key的设计</h3><ul><li><p>禁止包含特殊字符(比如空格、换行、单双引号以及其他转义字符)</p></li><li><p>建议风格一致 建议同时大驼峰、同时小驼峰或者下划线；是项目级别的统一</p></li><li><p>key不能太长也不能太短,<strong>键名越长越占资源，太短可读性太差</strong></p></li><li><p>key 单词与单词之间以冒号<code>：</code>分开。市面上的redis可视化工具，<code>:</code>比较容易进行下级选择</p></li><li><p>redis使用的时候注意命名空间，<strong>一个项目一个命名空间，项目内业务不同命名空间也不同</strong>。</p></li></ul><p>一般情况下：</p><ul><li>第一段放置项目名或缩写 如 project</li><li>第二段把表名转换为key前缀 如, user:</li><li>第三段放置用于区分区key的字段,对应mysql中的主键的列名,如userid</li><li>第四段放置主键值,如18,16</li></ul><p>结合起来 PRO:USER:UID:18 就很清晰</p><h3 id="value设计" tabindex="-1"><a class="header-anchor" href="#value设计" aria-hidden="true">#</a> value设计</h3><ul><li><p>拒绝大key操作，禁用超过10K的string大key(虽然redis支持512MB大小的string)，如果1mb的key每秒重复写入10次，就会导致写入网络IO达10MB。</p></li><li><p>设计key时使用合适的数据类型(在资源利用和性能之间作平衡)。例如：将一个普通字符串弄成hash类型进行存储这是不合理的</p></li><li><p>控制key的生命周期，例如：key设置为永不过期是不合理的，也不建议过期时间全部一样，避免key大面积失效，mysql被打满</p></li><li><p>控制value长度。例如string类型，如果value为&#39;8个字节的长整型&#39;则内部使用int类型，如果value为&#39;小于等于39个字节的字符串&#39;则内部使用embstr类型，如果value为&#39;大于39个字节的字符串&#39;则内部使用raw类型。这样能很好的利用redis的性能。</p></li></ul><h4 id="数据按需存储" tabindex="-1"><a class="header-anchor" href="#数据按需存储" aria-hidden="true">#</a> 数据按需存储</h4><p>不需要的数据千万不要存储在redis，只会浪费内存空间</p><h3 id="命令使用" tabindex="-1"><a class="header-anchor" href="#命令使用" aria-hidden="true">#</a> 命令使用</h3><ul><li>禁止使用keys、flushall、hmgetall等命令</li></ul><blockquote><p>为防止业务研发的误操作，通常可以在交付redis实例之前将默认命令rename掉；而真正需要删除或者遍历key时可以使用scan家族命令</p></blockquote><ul><li>慎用hgetall、lrange、smembers、zrange等命令</li></ul><blockquote><p>除非业务场景需要，尽量不要使用这些命令。如果没有控制好会导致操作量过大，形成阻塞。</p></blockquote><h3 id="项目实战" tabindex="-1"><a class="header-anchor" href="#项目实战" aria-hidden="true">#</a> 项目实战</h3><ul><li>项目redis使用问题</li></ul><blockquote><p>当前的使用方式是，每个接入的应用要配置核心项目的redis配置。这样是不合理的，核心项目的redis应该只能在核心项目中使用，对外应该是提供api接口或者rpc进行访问。</p></blockquote><ul><li>注意key的过期时间设置</li></ul><blockquote><p>在报名等高峰期的时候，key值设置过短容易造成<strong>缓存穿透</strong>，导致大量请求直接打到mysql数据库。</p></blockquote><ul><li>提防缓存穿透</li></ul><blockquote><p>空值也应该被缓存，经常使用会只给有数据的结果进行缓存，结果导致空数据无法缓存，相同查询直接每次都到达数据库，所以</p></blockquote><ul><li>不建议将redis做为消息队列</li></ul><blockquote><p>如没有非常特殊的需求，严禁将 Redis 当作消息队列使用。redis 当作消息队列使用，会有容量、网络、效率、功能方面的多种问题。 如需要消息队列，可使用高吞吐的 Kafka 或者高可靠的 RocketMQ，nsq,(花园同步有时间前后要求，且量不大才使用的)。</p></blockquote><h4 id="查询使用" tabindex="-1"><a class="header-anchor" href="#查询使用" aria-hidden="true">#</a> 查询使用</h4><h5 id="线上redis禁止使用keys正则匹配操作" tabindex="-1"><a class="header-anchor" href="#线上redis禁止使用keys正则匹配操作" aria-hidden="true">#</a> 线上Redis禁止使用Keys正则匹配操作</h5><blockquote><p>redis是单线程处理，在线上Key数量较多时，操作效率极低【时间复杂度为O(N)】，该命令一旦执行会严重阻塞线上其它命令的正常请求，而且在高QPS情况下会直接造成redis服务崩溃！如果有类似需求，可以使用scan命令代替。</p></blockquote><h2 id="参考资料" tabindex="-1"><a class="header-anchor" href="#参考资料" aria-hidden="true">#</a> 参考资料</h2>`,61),p={href:"https://blog.csdn.net/qq_36042938/article/details/108845426",target:"_blank",rel:"noopener noreferrer"};function h(u,k){const l=i("ExternalLinkIcon");return r(),d("div",null,[c,e("ul",null,[e("li",null,[e("a",p,[o("https://blog.csdn.net/qq_36042938/article/details/108845426"),s(l)])])])])}const f=a(n,[["render",h],["__file","use-rule.html.vue"]]);export{f as default};
